import { useState } from "react";

export default function SearchAppointment() {
  const [phone, setPhone] = useState("");
  const [result, setResult] = useState(null);

  const handleSearch = async () => {
    const res = await fetch(`http://127.0.0.1:8000/api/appointments/${phone}`);
    const data = await res.json();
    setResult(data);
  };

  return (
    <div>
      <h3 className="text-lg font-semibold mb-4">Search Appointment</h3>

      <div className="flex gap-3 mb-4">
        <input
          value={phone}
          onChange={(e) => setPhone(e.target.value)}
          placeholder="Enter phone"
          className="border p-3 rounded-lg w-full focus:ring-2 focus:ring-blue-400"
        />

        <button
          onClick={handleSearch}
          className="bg-blue-600 text-white px-4 rounded-lg"
        >
          Search
        </button>
      </div>

      {result && (
        <div className="p-4 border rounded-lg shadow">
          <p><strong>Name:</strong> {result.patient_name}</p>
          <p><strong>Phone:</strong> {result.phone}</p>
          <p><strong>Date:</strong> {result.date}</p>
          <p><strong>Treatment:</strong> {result.treatment}</p>
        </div>
      )}
    </div>
  );
}
